 * chunk）/ keepalive / rate-limit recovery 多路觸發，且節流時間戳只在成功
 * 後更新——送出一旦開始失敗，時間閘門全開，並發呼叫在「draft 失敗 →
 * !placeholder → sendMessage」的降級分支各自建立 placeholder，一口氣冒出
 * 十幾則相同內容的訊息。latch 讓降級分支天然序列化，TOCTOU 消失。
 */
export function coalesceAsyncRunner(
  fn: () => Promise<void>,
  isCancelled: () => boolean = () => false,
): () => Promise<void> {
  let inFlight = false;
  let pending = false;
  const run = async (): Promise<void> => {
    if (isCancelled()) return;
    if (inFlight) {
      pending = true;
      return;
    }
    inFlight = true;
    try {
      await fn();
    } finally {
      inFlight = false;
      if (pending) {
        pending = false;
        if (!isCancelled()) void run();
      }
    }
  };
  return run;
}
