/** One tool call's progress within the in-flight turn. */
export interface ToolEvent {
  /** ACP toolCallId when present, else a synthetic id for matching updates. */
  id: string;
  /** Human-readable tool name/title. */
  name: string;
  status: "running" | "completed" | "failed";
  /** Date.now() at tool_call start. */
  startedAt: number;
  /** Wall-clock ms once completed/failed; undefined while running. */
  elapsedMs?: number;
}

const TOOL_STATUS_EMOJI = {
  running: "⚙️",
  completed: "✅",
  failed: "❌",
} as const;

/**
 * Mark a running tool as completed/failed, stamping elapsed time. Matches by
 * ACP toolCallId; if the update carries no id (or none matches), falls back to
 * the most recent still-running entry so the line still transitions.
 */
function markToolDone(
  session: ChatSession,
  updId: string | undefined,
  status: "completed" | "failed",
): void {
  let entry = updId
    ? session.toolTimeline.find((t) => t.id === updId && t.status === "running")
    : undefined;
  if (!entry) {
    for (let i = session.toolTimeline.length - 1; i >= 0; i--) {
      if (session.toolTimeline[i].status === "running") {
        entry = session.toolTimeline[i];
        break;
      }
    }
  }
  if (entry) {
    entry.status = status;
    entry.elapsedMs = Date.now() - entry.startedAt;
  }
}

