 *      atomic on NTFS / POSIX fs.
 *
 * Concurrent calls for the same `filePath` are serialized via an
 * in-process promise chain so tmp files don't collide and we never
 * observe a torn write.
 *
 * Errors during step 2/3 are propagated; the caller decides whether to
 * retry or surface to the user. On step-3 failure we best-effort
 * unlink() the orphan tmp file so /tmp doesn't fill up over time.
 */
export async function atomicWriteJson(
  filePath: string,
  data: unknown,
): Promise<void> {
  const absPath = path.resolve(filePath);
  const prev = writePendingByPath.get(absPath) ?? Promise.resolve();
  const next = prev.then(async () => {
    await mkdir(path.dirname(absPath), { recursive: true });
    const tmpPath = `${absPath}.tmp-${process.pid}-${Date.now()}`;
    const body = JSON.stringify(data, null, 2) + "\n";
    try {
      await writeFile(tmpPath, body, "utf8");
      await renameWithWindowsRetry(tmpPath, absPath);
    } catch (err) {
      // Best-effort cleanup; ignore failures since tmpPath may not exist.
      await unlink(tmpPath).catch(() => {});
      throw err;
    }
  });
  // Attach a catch so an earlier failure doesn't poison subsequent writes:
  // each caller awaits its own `next`, but the chain's `prev` for future
  // writers should resolve either way.
  const chained = next.catch((err) => {
    console.error(`[atomicJson] atomicWriteJson(${absPath}) failed:`, err);
  });
  writePendingByPath.set(absPath, chained);
  // Compare-and-delete：settle 後 map 內仍是本次的 chain 才移除——否則
  // 每個寫過的唯一路徑（goal-state/*.json、per-chat 檔）永久留一個
  // resolved promise entry，map 只增不減。
  chained.finally(() => {
    if (writePendingByPath.get(absPath) === chained) writePendingByPath.delete(absPath);
  });
  await next;
}

/**
 * Small convenience for code that reads, mutates, and writes back under
 * the same serialization guarantee. The `update()` callback runs inside
 * the write chain, so concurrent update() calls on the same path are
 * serialized read-modify-write — no lost-update race.
 *
 * `initial` is used when the file does not exist or is malformed.
 */
export async function updateJson<T>(
  filePath: string,
  initial: () => T,
  update: (current: T) => T | Promise<T>,
): Promise<T> {
  const absPath = path.resolve(filePath);
  const prev = writePendingByPath.get(absPath) ?? Promise.resolve();
  let result: T;
  const next = prev.then(async () => {
    const current = await readJsonOrDefault<T>(absPath, initial);
    const updated = await update(current);
    result = updated;
    await mkdir(path.dirname(absPath), { recursive: true });
    const tmpPath = `${absPath}.tmp-${process.pid}-${Date.now()}`;
    const body = JSON.stringify(updated, null, 2) + "\n";
    try {
      await writeFile(tmpPath, body, "utf8");
      await renameWithWindowsRetry(tmpPath, absPath);
    } catch (err) {
      await unlink(tmpPath).catch(() => {});
      throw err;
    }
  });
